INSERT INTO message_templates (name, content, category, created_by) VALUES
('פנייה ראשונית', 'היי {שם}, זה Prime Property 🏠 קיבלתי את הפרטים שלך ואשמח לעזור לך למצוא דירה. מתי נוח לך לדבר?', 'customers', '30300ca7-6c59-41e4-99dd-ef59ea3ea349'),
('עדכון חיפוש', 'היי {שם}, רציתי לעדכן אותך שאני עובד על החיפוש שלך ויש כמה אפשרויות מעניינות. נדבר?', 'customers', '30300ca7-6c59-41e4-99dd-ef59ea3ea349'),
('הצעת דירה חדשה', 'היי {שם}, מצאתי דירה שיכולה להתאים לך! 🏡 אשלח לך פרטים?', 'customers', '30300ca7-6c59-41e4-99dd-ef59ea3ea349'),
('תיאום סיור', 'היי {שם}, בנוגע לדירה שדיברנו עליה — מתי נוח לך לתאם סיור? יש לי פנויות השבוע 📅', 'customers', '30300ca7-6c59-41e4-99dd-ef59ea3ea349'),
('פולו-אפ אחרי סיור', 'היי {שם}, מה חשבת על הדירה שראינו? אשמח לשמוע 😊 אם לא מתאים, יש לי עוד אפשרויות.', 'customers', '30300ca7-6c59-41e4-99dd-ef59ea3ea349'),
('שמירת קשר', 'היי {שם}, לא שכחתי אותך 😊 עדיין מחפש/ת דירה? אשמח לחדש את החיפוש.', 'customers', '30300ca7-6c59-41e4-99dd-ef59ea3ea349'),

